const items = $input.all();
const dashboard = items[0]?.json || {};
const alertasData = items[1]?.json || {};

const webhookData = $('Webhook - Cierre de turno').first().json.body || {};
const turno = webhookData.turno || 'manana';
const supervisor = webhookData.supervisor || 'No especificado';

const kpis = dashboard.kpis || {};
const meteo = dashboard.meteo || {};
const seguridad = dashboard.seguridad || {};
const alertas = Array.isArray(alertasData) ? alertasData : (alertasData.alertas || []);

const contexto = {
  turno,
  supervisor,
  fecha: new Date().toISOString().split('T')[0],
  produccion: {
    produccion_hoy_ton: kpis.produccion_hoy_ton || 0,
    produccion_mes_ton: kpis.produccion_mes_ton || 0,
    target_mes_ton: kpis.target_mes_ton || 433,
    concentracion_li: kpis.concentracion_promedio_li || 859
  },
  pozos: {
    activos: kpis.pozos_activos || 5,
    total: kpis.pozos_total || 7
  },
  meteo: {
    temperatura_c: meteo.temperatura_c,
    viento_kmh: meteo.velocidad_viento_kmh,
    evaporacion: meteo.tasa_evaporacion_mm_dia
  },
  seguridad: {
    personal: seguridad.personal_en_sitio || kpis.personal_en_sitio || 234,
    dias_sin_lti: seguridad.dias_sin_lti || 187
  },
  alertas: {
    total: alertas.length,
    criticas: alertas.filter(a => a.severidad === 'critica').length,
    altas: alertas.filter(a => a.severidad === 'alta').length
  }
};

const groqBody = {
  model: 'llama-3.1-8b-instant',
  messages: [
    {
      role: 'system',
      content: 'Genera un resumen ejecutivo de turno de 200 palabras en espanol para una operacion de litio en el Salar del Hombre Muerto, Catamarca, Argentina, a 4000 msnm. La planta HMW (Hombre Muerto West) de Galan Lithium incluye 7 pozos de extraccion de salmuera, 6 pozas de evaporacion en 4 etapas, y planta de nanofiltracion. Incluye: produccion, estado de pozos y pozas, alertas relevantes, condiciones meteorologicas, personal, y recomendaciones para el proximo turno. Se conciso, profesional y tecnico.'
    },
    {
      role: 'user',
      content: 'Genera el resumen ejecutivo del turno con los siguientes datos operativos: ' + JSON.stringify(contexto)
    }
  ],
  temperature: 0.4,
  max_tokens: 800
};

return [{
  json: {
    turno,
    supervisor,
    fecha: contexto.fecha,
    groq_body: groqBody,
    contexto
  }
}];

const llmResponse = $input.first().json;
const resumenIA = llmResponse.choices[0].message.content;

const ctx = $('Preparar contexto LLM').first().json;

const horarios = {
  manana: '06:00 - 14:00',
  tarde: '14:00 - 22:00',
  noche: '22:00 - 06:00'
};

const reporte = {
  turno: ctx.turno,
  horario: horarios[ctx.turno] || ctx.turno,
  fecha: ctx.fecha,
  supervisor: ctx.supervisor,
  resumen_ia: resumenIA,
  produccion_ton: ctx.contexto.produccion.produccion_hoy_ton,
  personal_presente: ctx.contexto.seguridad.personal,
  alertas_generadas: ctx.contexto.alertas.total,
  alertas_resueltas: 0,
  novedades: [],
  estado: 'borrador',
  generado_por: 'n8n-groq-llama3.1',
  timestamp: new Date().toISOString()
};

return [{ json: reporte }];
